import{_ as a,o as i,c as t,ag as n}from"./chunks/framework.B9unkguw.js";const h=JSON.parse('{"title":"Fly View","description":"","frontmatter":{},"headers":[],"relativePath":"tr/qgc-user-guide/fly_view/fly_view.md","filePath":"tr/qgc-user-guide/fly_view/fly_view.md"}'),o={name:"tr/qgc-user-guide/fly_view/fly_view.md"};function r(l,e,s,d,m,c){return i(),t("div",null,e[0]||(e[0]=[n('<h1 id="fly-view" tabindex="-1">Fly View <a class="header-anchor" href="#fly-view" aria-label="Permalink to &quot;Fly View&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Having trouble?</p><p>For connection issues, see <a href="./../troubleshooting/vehicle_connection.html">Connection Problems</a>. For mission resume issues during flight, see <a href="./../troubleshooting/resume_mission.html">Resume Mission Failures</a>.</p></div><p>The Fly View is used to command and monitor the vehicle.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><ul><li><strong><a href="./fly_view_toolbar.html">Toolbar</a>:</strong> The toolbar is at the top of the screen. It provides controls to select views, show flight status and mode as well as the status of the main components of the vehicle.</li><li><strong><a href="./fly_tools.html">Vehicle Actions</a>:</strong> Allows you command the vehicle to take a specific action.</li><li><strong><a href="./instrument_panel.html">Instrument Panel</a>:</strong> A widget that displays vehicle telemetry.</li><li><strong><a href="./hud.html">Attitude/Compass</a>:</strong> A widget that provides virtual horizon and heading information.</li><li><strong><a href="./camera_tools.html">Camera Tools</a></strong>: A widget for switching between still and video modes, starting/stopping capture, and controlling camera settings.</li><li><strong><a href="./video.html">Video</a>:</strong> Display the video from the vehicle. Allows you to toggle between video or map as the main display.</li><li><strong>Map:</strong> Displays the positions of all connected vehicles and the mission for the current vehicle. <ul><li>You can drag the map to move it around (the map automatically re-centres on the vehicle after a certain amount of time).</li><li>You can zoom the map in and out using the zoom buttons, mouse wheel, track pad or pinch on a tablet.</li><li>Once flying, you can click on the map to set a <a href="#map_actions">Go to</a> or <a href="#map_actions">Orbit at</a> location.</li></ul></li></ul><p>There are a number of other elements that are not displayed by default and are only displayed in certain conditions or for certain vehicle types.</p><h2 id="islemler-gorevler" tabindex="-1">İşlemler/Görevler <a class="header-anchor" href="#islemler-gorevler" aria-label="Permalink to &quot;İşlemler/Görevler&quot;">​</a></h2><p>Aşağıdaki bölümler, Uçuş Ekranı&#39;nda genel işlemlerin / görevlerin nasıl gerçekleştirileceğini açıklamaktadır.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Many of the available options depend on both the vehicle type and its current state.</p></div><h3 id="map_actions" tabindex="-1">Actions associated with a map position <a class="header-anchor" href="#map_actions" aria-label="Permalink to &quot;Actions associated with a map position {#map_actions}&quot;">​</a></h3><p>There are a number of actions which can be taken which are associated with a specific position on the map. To use these actions:</p><ol><li>Click on the map at a specific position</li><li>A popup will display showing you the list of available actions</li><li>Select the action you want</li><li>Confirm the action</li></ol><p>Examples of map position actions are Go To Location, Orbit and so forth.</p><h3 id="pause" tabindex="-1">Pause <a class="header-anchor" href="#pause" aria-label="Permalink to &quot;Pause&quot;">​</a></h3><p>You can pause most operations, including taking off, landing, RTL, mission execution, orbit at location. Duraklatıldığında aracın davranışı aracın tipine bağlıdır, genellikle multikopterler havada asılı kalırken sabit kanatlar çember çizer.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Bir <em>Goto location</em> operasyonunu durduramazsınız.</p></div><p>Durdurmak için:</p><ol><li><em>Fly Tools</em>&#39;dan <strong>Pause</strong> butonuna basın.</li><li>İsterseniz yeni bir yüksekliği sağda bulunan dikey kaydırıcıyla ayarlayabilirsiniz.</li><li><a href="./fly_tools.html#confirmation">Confirm</a> the action.</li></ol><h3 id="gorevler" tabindex="-1">Görevler <a class="header-anchor" href="#gorevler" aria-label="Permalink to &quot;Görevler&quot;">​</a></h3><h4 id="start_mission" tabindex="-1">Görevi Başlatma <a class="header-anchor" href="#start_mission" aria-label="Permalink to &quot;Görevi Başlatma {#start_mission}&quot;">​</a></h4><p>You can start a mission when the vehicle is landed (the start mission confirmation button is often displayed by default).</p><p>Yerdeki bir aracın görevini başlatmak için:</p><ol><li><p><em>Fly Tools</em>&#39;dan <strong>Action</strong> butonuna basın</p></li><li><p>İletişim kutusundan <em>Start Mission</em>&#39;ı seçin.</p></li><li><p><a href="./fly_tools.html#confirmation">Confirm</a> the action to start the mission.</p></li></ol><h4 id="continue_mission" tabindex="-1">Göreve Devam Etme (Continue Mission) <a class="header-anchor" href="#continue_mission" aria-label="Permalink to &quot;Göreve Devam Etme (Continue Mission) {#continue_mission}&quot;">​</a></h4><p>You can <em>continue</em> mission from the <em>next</em> waypoint when you&#39;re flying (the <em>Continue Mission</em> confirmation button is often displayed by default after you takeoff).</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Continue ve <a href="#resume_mission">Resume mission</a> farklıdır! Continue komutu durdurulmuş bir görevi tekrar başlatmak veya zaten kalkmış bir araç için yani kalkış görevi komutunu kaçırmış durumdaysanız kullanılır. Resume mission is used when you&#39;ve used a RTL or landed midway through a mission (e.g. for a battery change) and then wish to continue the next mission item (i.e. it takes you to where you were up to in the mission, rather than continuing from your place in the mission).</p></div><p>Görevinize aşağıdakileri yaparak devam edebilirsiniz (hali hazırda bir görevde değilseniz!):</p><ol><li><p><em>Fly Tools</em>&#39;dan <strong>Action</strong> butonuna basın</p></li><li><p>İletişim kutusundan <em>Continue Mission</em>&#39;ı seçin.</p></li><li><p><a href="./fly_tools.html#confirmation">Confirm</a> the action to continue the mission.</p></li></ol><h4 id="resume_mission" tabindex="-1">Göreve Devam Etme (Resume Mission) <a class="header-anchor" href="#resume_mission" aria-label="Permalink to &quot;Göreve Devam Etme (Resume Mission) {#resume_mission}&quot;">​</a></h4><p><em>Resume Mission</em> is used to resume a mission after performing an <a href="./hud.html#rtl">RTL/Return</a> or <a href="./hud.html#land">Land</a> from within a mission (in order, for example, to perform a battery change).</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Eğer bataryayı değiştiricekseniz, bataryanın bağlantısını kestikten sonra QGC ile aracın bağlantısını <strong>kesmeyin</strong>. Yeni bataryayı yerleştirdikten sonra <em>QGroundControl</em> cihazı tekrar tespit edip, bağlantıyı otomatik olarak yeniden kuracaktır.</p></div><p>İnişten sonra size görev planını cihazdan kaldırma, cihazda bırakma ya da göreve kaldığı yerden devam etme seçeneklerini sunan bir <em>Flight Plan complete</em> iletişim kutusu karşınıza çıkacaktır.</p><p>If you select to resume the mission, then <em>QGroundControl</em> will rebuild the mission and upload it to the vehicle. Then <a href="./fly_tools.html#confirmation">confirm</a> the action to continue the mission.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Bir görev, basit bir şekilde aracın son gerçekleştirdiği görev aşamasından devam edemez, çünkü son yapılan aşamada görevin sonraki aşamalarına etki edebilecek birden fazla etken olabilir (ör. hız komutları ya da kameranın kontrol komutları). Basit bir şekilde devam etmek yerine, <em>QGroundControl</em> son gerçekleştirilen görev aşamasından başlayarak, ilgili komutları da dikkate alarak görevi tekrar yapılandırır.</p></div><h4 id="resume_mission_prompt" tabindex="-1">İnişten Sonra Görevi Kaldırma <a class="header-anchor" href="#resume_mission_prompt" aria-label="Permalink to &quot;İnişten Sonra Görevi Kaldırma {#resume_mission_prompt}&quot;">​</a></h4><p>Görev bittikten sonra aracın inişi ve devre dışı bırakılmasının ardından görevi araçtan kaldırmanız istenecektir. This is meant to prevent issues where stale missions are unknowingly left on a vehicle, potentially resulting in unexpected behavior.</p><h3 id="video_switcher" tabindex="-1">Videoyu Görüntüleme <a class="header-anchor" href="#video_switcher" aria-label="Permalink to &quot;Videoyu Görüntüleme {#video_switcher}&quot;">​</a></h3><p>Video akışı etkinleştirildiğinde, <em>QGroundControl</em> haritanın sol altında bulunan &quot;videoya geçiş penceresi&quot;nde videoyu göstermeye başlıyacaktır. You can press the switcher anywhere to toggle <em>Video</em> and <em>Map</em> to foreground.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>video akışı <a href="./../settings_view/general.html#video">Application Settings &gt; General tab &gt; Video</a>&#39;dan etkinleştirilebilir/düzenlenebilir.</p></div><p>Video görüntüsünü geçiş penceresindeki kontrolleri kullanararak daha da düzenleyebilirsiniz:</p><ul><li>Resize the switcher by dragging the icon in the top right corner.</li><li>Hide the switcher by pressing the toggle icon in the lower left.</li><li>Sol üst köşedeki ikona basarak video geçiş pencersini ayırabilirsiniz. (ayrıldığında, işletim sisteminizdeki her hangi bir pencere gibi hareket ettirip tekrar boyutlandırabilirsiniz). Eğer ayrılan pencereyi kapatırsanız, geçiş penceresi tekrardan QGC uçuş görünüme sabitlenecektir.</li></ul><h3 id="video-kaydı" tabindex="-1">Video Kaydı <a class="header-anchor" href="#video-kaydı" aria-label="Permalink to &quot;Video Kaydı&quot;">​</a></h3><p>Eğer araç ve kamera tarafından destekleniyorsa, <em>QGroundControl</em> kendiliğinden video kaydını başlatıp durdurabilirsiniz. Ayrıca <em>QGroundControl</em> videoyu yayınlayıp, yerel dosyalara kaydedebilir.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Kameranın kendisinde kaydedilen video daha kaliteli olacak olsa da, yüksek ihtimalle yer istasyonunun daha büyük kayıt kapasitesi olacaktır.</p></div><h4 id="video-akısını-kaydetme-gcs-de" tabindex="-1">Video Akışını Kaydetme (GCS&#39;de) <a class="header-anchor" href="#video-akısını-kaydetme-gcs-de" aria-label="Permalink to &quot;Video Akışını Kaydetme (GCS&#39;de)&quot;">​</a></h4><p>Video stream recording is controlled on the <a href="./hud.html#video_instrument_page">video stream instrument page</a>. Yeni bir video kaydı başlatmak için kırmızı daireye tıklayın (daireye her tıklanıldığında yeni bir video dosyası oluşturulur); kayıt devam ederken çember kırmızı bir kareye dönüşecektir.</p><p>Video akışı kaydı <a href="./../settings_view/general.html">Application Settings &gt; General tab</a>&#39;dan düzenlenir:</p><ul><li><p><a href="./../settings_view/general.html#video-recording">Video Recording</a> - kayıt dosyası formatını ve depolama sınırlarını belirtir.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Videolar varsayılan olarak Matroska format (.mkv) olarak kaydedilir. Bu format, hata durumunda bozulmaya karşı nispeten dayanıklıdır.</p></div></li><li><p><a href="./../settings_view/general.html#miscellaneous">Miscellaneous</a> - Video <strong>Application Load/Save Path</strong>&#39;e kaydedilir.</p></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Kaydedilen video, sadece video akışının kendisini içerir. QGroundControl uygulamasının öğeleriyle videoyu kaydetmek için başka bir ekran kaydı uygulaması kullanmanız gerekir.</p></div><h4 id="videoyu-kamerada-kaydetme" tabindex="-1">Videoyu Kamerada Kaydetme <a class="header-anchor" href="#videoyu-kamerada-kaydetme" aria-label="Permalink to &quot;Videoyu Kamerada Kaydetme&quot;">​</a></h4><p>Start/stop video recording <em>on the camera itself</em> using the <a href="./hud.html#camera_instrument_page">camera instrument page</a>. İlk olarak video moduna geçiş yapın, ardından kırmızı butona basarak kaydı başlatabilirsiniz.</p>',51)]))}const p=a(o,[["render",r]]);export{h as __pageData,p as default};
